starterCss:
/* Create a blend mode effect:
   - Container: 300x200px, position relative
   - Layer 1: red gradient, covers full container
   - Layer 2: blue gradient, covers full container, uses 'multiply' blend mode
   - Label: centered on top */
.blend-container {
  width: 300px;
  height: 200px;
  position: relative;
  border-radius: 8px;
  overflow: hidden;
}

referenceSolutions:
.blend-container {
  width: 300px;
  height: 200px;
  position: relative;
  border-radius: 8px;
  overflow: hidden;
}
.blend-layer {
  position: absolute;
  inset: 0;
}
.layer-1 {
  background: linear-gradient(135deg, rgb(255, 0, 0), rgb(255, 165, 0));
}
.layer-2 {
  background: linear-gradient(225deg, rgb(0, 0, 255), rgb(0, 255, 255));
  mix-blend-mode: multiply;
}
.blend-label {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: rgb(255, 255, 255);
  font-weight: 700;
  font-size: 24px;
  z-index: 1;
}

.blend-container {
  width: 300px;
  height: 200px;
  position: relative;
  border-radius: 8px;
  overflow: hidden;
}
.blend-layer {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
}
.layer-1 {
  background: linear-gradient(135deg, red, orange);
}
.layer-2 {
  background: linear-gradient(225deg, blue, cyan);
  mix-blend-mode: multiply;
}
.blend-label {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: white;
  font-weight: bold;
  font-size: 24px;
  z-index: 1;
}

